using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9 renamed the default discriminator property from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", so keep the old name.
            b.HasDiscriminator<string>("Discriminator");

            // EF9 removed the discriminator from the JSON id by default.
            // Existing documents have id values like "Product|123", so opt back in.
            b.HasDiscriminatorInJsonId();

            // EF9 maps the key property directly to the JSON "id" field.
            // Existing documents store Id separately and use a shadow __id property.
            // Preserve that layout so EF can still read old documents.
            b.HasShadowId();
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

